import os
import json
import time
import hashlib
from functools import wraps
from flask import Flask, request, jsonify

app = Flask(__name__)

class SecureCache:
    def __init__(self, cache_dir='cache', default_ttl=3600):
        self.cache_dir = cache_dir
        self.default_ttl = default_ttl
        os.makedirs(cache_dir, exist_ok=True)
    
    def _get_cache_key(self, key):
        """Generate a safe filename from cache key"""
        hash_key = hashlib.sha256(key.encode()).hexdigest()
        return os.path.join(self.cache_dir, f"{hash_key}.json")
    
    def _is_expired(self, cache_data):
        """Check if cache entry has expired"""
        if 'expires_at' not in cache_data:
            return True
        return time.time() > cache_data['expires_at']
    
    def get(self, key):
        """Retrieve data from cache"""
        cache_file = self._get_cache_key(key)
        
        if not os.path.exists(cache_file):
            return None
        
        try:
            with open(cache_file, 'r') as f:
                cache_data = json.load(f)
            
            if self._is_expired(cache_data):
                self.delete(key)
                return None
            
            return cache_data.get('data')
        except (json.JSONDecodeError, IOError, KeyError):
            return None
    
    def set(self, key, data, ttl=None):
        """Store data in cache with expiration"""
        if ttl is None:
            ttl = self.default_ttl
        
        cache_file = self._get_cache_key(key)
        cache_data = {
            'data': data,
            'created_at': time.time(),
            'expires_at': time.time() + ttl
        }
        
        try:
            with open(cache_file, 'w') as f:
                json.dump(cache_data, f, separators=(',', ':'))
            return True
        except (IOError, TypeError):
            return False
    
    def delete(self, key):
        """Delete cache entry"""
        cache_file = self._get_cache_key(key)
        try:
            if os.path.exists(cache_file):
                os.remove(cache_file)
            return True
        except IOError:
            return False
    
    def clear(self):
        """Clear all cache entries"""
        try:
            for filename in os.listdir(self.cache_dir):
                if filename.endswith('.json'):
                    os.remove(os.path.join(self.cache_dir, filename))
            return True
        except IOError:
            return False


cache = SecureCache(cache_dir='api_cache', default_ttl=300)


def cached_response(ttl=None, key_prefix=''):
    """Decorator to cache API responses"""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key = f"{key_prefix}:{f.__name__}:{request.path}:{request.query_string.decode()}"
            
            cached_data = cache.get(cache_key)
            if cached_data is not None:
                return jsonify(cached_data), 200
            
            response_data = f(*args, **kwargs)
            
            if isinstance(response_data, tuple):
                data, status_code = response_data
            else:
                data = response_data
                status_code = 200
            
            if status_code == 200:
                cache.set(cache_key, data, ttl=ttl)
            
            return jsonify(data), status_code
        
        return decorated_function
    return decorator


