def delete_cache_entry():
    """Delete specific cache entry"""
    data = request.get_json()
    if not data or 'key' not in data:
        return jsonify({'status': 'error', 'message': 'Key required'}), 400
    
    if cache.delete(data['key']):
        return jsonify({'status': 'success', 'message': 'Cache entry deleted'})
    else:
        return jsonify({'status': 'error', 'message': 'Failed to delete cache entry'}), 500


